checker_dsl:
EXISTS (`assignment expression AE`) {
  AND {
    EXISTS (`variable access DEST`) {
      (`DEST is the destination of AE`)
    },
    EXISTS (`variable access SRC`) {
      (`SRC is the source of AE`)
    },
    EXISTS (`variable V`) {
      AND {
        (`V is the variable of DEST`),
        (`V is the variable of SRC`)
      }
    },
    EXISTS (`variable access LEFT`, `variable access RIGHT`) {
      AND {
        (`LEFT is DEST`),
        (`RIGHT is SRC`),
        OR {
          AND {
            EXISTS (`assignment expression ASSIGN`) {
              AND {
                (`ASSIGN is AE`),
                (`LEFT is the destination of ASSIGN`),
                (`RIGHT is the source of ASSIGN`)
              }
            }
          },
          AND {
            EXISTS (`variable access OUTERLEFT`, `variable access OUTERRIGHT`) {
              AND {
                (`toCompare(OUTERLEFT, OUTERRIGHT) holds`),
                (`LEFT is the qualifier of OUTERLEFT`),
                (`RIGHT is the qualifier of OUTERRIGHT`)
              }
            }
          }
        },
        OR {
          AND {
            EXISTS (`expression Q1`, `expression Q2`) {
              AND {
                (`Q1 is the qualifier of LEFT`),
                (`Q2 is the qualifier of RIGHT`),
                (`sameVariable(Q1, Q2) holds`)
              }
            }
          },
          AND {
            EXISTS (`reference type ENCLOSINGTYPE`) {
              AND {
                OR {
                  AND {
                    EXISTS (`this access THIS1`) {
                      AND {
                        (`THIS1 is the qualifier of LEFT`)
                      }
                    },
                    (`ENCLOSINGTYPE is the type of THIS1`)
                  },
                  AND {
                    (`LEFT has no qualifier`),
                    EXISTS (`callable C1`) {
                      AND {
                        (`C1 is the enclosing callable of LEFT`),
                        (`ENCLOSINGTYPE is the declaring type of C1`)
                      }
                    }
                  }
                },
                OR {
                  AND {
                    EXISTS (`this access THIS2`) {
                      AND {
                        (`THIS2 is the qualifier of RIGHT`)
                      }
                    },
                    (`ENCLOSINGTYPE is the type of THIS2`)
                  },
                  AND {
                    (`RIGHT has no qualifier`),
                    EXISTS (`callable C2`) {
                      AND {
                        (`C2 is the enclosing callable of RIGHT`),
                        (`ENCLOSINGTYPE is the declaring type of C2`)
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
